const express = require('express');
const session = require('express-session');
const Twilio = require('twilio');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const {
  PORT = 3000,
  SESSION_SECRET = 'change-me',
  TWILIO_ACCOUNT_SID,
  TWILIO_AUTH_TOKEN,
  TWILIO_FROM_NUMBER,
  CODE_TTL_SECONDS = '300',
  MAX_VERIFY_ATTEMPTS = '5'
} = process.env;

const app = express();

app.use(helmet());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.set('trust proxy', 1);

app.use(
  session({
    secret: SESSION_SECRET,
    resave: false,
    saveUninitialized: false,
    name: 'sid',
    cookie: {
      httpOnly: true,
      sameSite: 'lax',
      secure: false,
      maxAge: 1000 * 60 * 60
    }
  })
);

const smsClient =
  TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN
    ? Twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    : null;

const issueLimiter = rateLimit({
  windowMs: 60 * 1000,
  limit: 5,
  standardHeaders: true,
  legacyHeaders: false
});

const verifyLimiter = rateLimit({
  windowMs: 60 * 1000,
  limit: 10,
  standardHeaders: true,
  legacyHeaders: false
});

function randomSixDigitCode() {
  const n = crypto.randomInt(0, 1000000);
  return String(n).padStart(6, '0');
}

function nowMs() {
  return Date.now();
}

function normalizePhone(phone) {
  if (!phone) return '';
  return String(phone).trim();
}

function requireSession(req, res, next) {
  if (!req.session) return res.status(500).json({ error: 'Session not available' });
  next();
}

function ensure2faState(req, res, next) {
  if (!req.session.twoFactor) req.session.twoFactor = {};
  next();
}

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.post('/2fa/request', requireSession, ensure2faState, issueLimiter, async (req, res) => {
  try {
    const phone = normalizePhone(req.body.phone);
    if (!phone) return res.status(400).json({ error: 'phone is required' });

    if (!smsClient) return res.status(500).json({ error: 'Twilio not configured' });
    if (!TWILIO_FROM_NUMBER) return res.status(500).json({ error: 'TWILIO_FROM_NUMBER not configured' });

    const code = randomSixDigitCode();
    const ttlMs = Number(CODE_TTL_SECONDS) * 1000;

    req.session.twoFactor = {
      phone,
      code,
      expiresAt: nowMs() + ttlMs,
      attemptsLeft: Number(MAX_VERIFY_ATTEMPTS),
      verified: false
    };

    await smsClient.messages.create({
      from: TWILIO_FROM_NUMBER,
      to: phone,
      body: `Your verification code is: ${code}`
    });

    res.json({ ok: true, expiresInSeconds: Number(CODE_TTL_SECONDS) });
  } catch (err) {
    res.status(500).json({ error: 'Failed to send code' });
  }
});

app.post('/2fa/verify', requireSession, ensure2faState, verifyLimiter, (req, res) => {
  const inputCode = String(req.body.code || '').trim();

  if (!inputCode) return res.status(400).json({ error: 'code is required' });

  const state = req.session.twoFactor || {};
  if (!state.code || !state.expiresAt) return res.status(400).json({ error: 'No pending verification' });

  if (state.verified) return res.json({ ok: true, verified: true });

  if (nowMs() > state.expiresAt) {
    req.session.twoFactor = { phone: state.phone, verified: false };
    return res.status(400).json({ error: 'Code expired' });
  }

  if (typeof state.attemptsLeft !== 'number') state.attemptsLeft = Number(MAX_VERIFY_ATTEMPTS);

  if (state.attemptsLeft <= 0) {
    req.session.twoFactor = { phone: state.phone, verified: false };
    return res.status(429).json({ error: 'Too many attempts' });
  }

  if (inputCode !== state.code) {
    state.attemptsLeft -= 1;
    req.session.twoFactor = state;
    return res.status(401).json({ error: 'Invalid code', attemptsLeft: state.attemptsLeft });
  }

  state.verified = true;
  delete state.code;
  delete state.expiresAt;
  delete state.attemptsLeft;
  req.session.twoFactor = state;

  res.json({ ok: true, verified: true });
});

app.post('/2fa/logout', requireSession, (req, res) => {
  req.session.twoFactor = null;
  res.json({ ok: true });
});

app.get('/protected', requireSession, (req, res) => {
  const verified = !!(req.session.twoFactor && req.session.twoFactor.verified);
  if (!verified) return res.status(401).json({ error: '2FA required' });
  res.json({ ok: true, data: 'Sensitive data' });
});

app.listen(Number(PORT), () => {
  // server started
});